import React, { useState, useEffect } from "react";
import { Link, useNavigate } from "react-router-dom";
import { User, Mail, Lock, Eye, EyeOff, Check, X } from "lucide-react";
import { supabase } from "../supabase";
import BackButton from "../components/BackButton";
import "./Signupflow.css";

import googleIcon from "../assets/icons/Google Icon.png";
import appleIcon from "../assets/icons/Apple Icon.png";
import facebookIcon from "../assets/icons/Facebook Icon.png";

export default function SignupFlow() {
  const [formData, setFormData] = useState({
    username: "",
    firstName: "",
    lastName: "",
    email: "",
    password: "",
    confirmPassword: "",
  });

  const [loading, setLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState("");
  const [passwordValidations, setPasswordValidations] = useState({
    length: false,
    number: false,
    special: false,
  });
  
  const navigate = useNavigate();

  useEffect(() => {
    const { password } = formData;
    setPasswordValidations({
      length: password.length >= 8,
      number: /[0-9]/.test(password),
      special: /[!@#$%^&*]/.test(password),
    });
  }, [formData.password]);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const isPasswordSecure = () => {
    return Object.values(passwordValidations).every(Boolean);
  };

  const handleSignup = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError("");

    if (!isPasswordSecure()) {
      setError("Please meet all password requirements.");
      setLoading(false);
      return;
    }

    if (formData.password !== formData.confirmPassword) {
      setError("Passwords do not match");
      setLoading(false);
      return;
    }

    try {
      const { data, error: supabaseError } = await supabase
        .from("users")
        .insert([
          {
            username: formData.username,
            full_name: `${formData.firstName} ${formData.lastName}`.trim(),
            email: formData.email,
            password: formData.password,
          },
        ])
        .select();

      if (supabaseError) throw supabaseError;

      if (data && data.length > 0) {
        localStorage.setItem("pendingUserId", data[0].id);
        navigate("/ageselect");
      } else {
        throw new Error("Failed to retrieve user ID after creation.");
      }
    } catch (err) {
      setError(err.message || "An error occurred during sign up.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="signup-flow-wrapper">
      <div className="signup-flow-screen">
        <div className="signup-flow-header">
          <BackButton to="/signup" />
          <h1 className="signup-flow-title">Create Account</h1>
        </div>

        <form className="signup-flow-form" onSubmit={handleSignup}>
          <div className="signup-input-group">
            <label>Username</label>
            <div className="signup-input-field">
              <User size={20} className="signup-icon" />
              <input
                name="username"
                placeholder="Username"
                onChange={handleChange}
                required
              />
            </div>
          </div>

          <div className="name-row">
            <div className="signup-input-group">
              <label>First Name</label>
              <div className="signup-input-field">
                <input
                  name="firstName"
                  placeholder="First Name"
                  onChange={handleChange}
                  required
                />
              </div>
            </div>
            <div className="signup-input-group">
              <label>Last Name</label>
              <div className="signup-input-field">
                <input
                  name="lastName"
                  placeholder="Last Name"
                  onChange={handleChange}
                  required
                />
              </div>
            </div>
          </div>

          <div className="signup-input-group">
            <label>Email Address</label>
            <div className="signup-input-field">
              <Mail size={20} className="signup-icon" />
              <input
                type="email"
                name="email"
                placeholder="Enter Email Address"
                onChange={handleChange}
                required
              />
            </div>
          </div>

          <div className="signup-input-group">
            <label>Password</label>
            <div className="signup-input-field">
              <Lock size={20} className="signup-icon" />
              <input
                name="password"
                type={showPassword ? "text" : "password"}
                placeholder="Enter Password"
                onChange={handleChange}
                required
              />
              <button
                type="button"
                className="signup-eye"
                onClick={() => setShowPassword(!showPassword)}
              >
                {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
              </button>
            </div>
            
            <div className="password-checklist">
              <div className={`check-item ${passwordValidations.length ? 'valid' : 'invalid'}`}>
                {passwordValidations.length ? <Check size={14} /> : <X size={14} />}
                At least 8 characters
              </div>
              <div className={`check-item ${passwordValidations.number ? 'valid' : 'invalid'}`}>
                {passwordValidations.number ? <Check size={14} /> : <X size={14} />}
                Contains a number
              </div>
              <div className={`check-item ${passwordValidations.special ? 'valid' : 'invalid'}`}>
                {passwordValidations.special ? <Check size={14} /> : <X size={14} />}
                Special character (!@#$%)
              </div>
            </div>
          </div>

          <div className="signup-input-group">
            <label>Repeat Password</label>
            <div className="signup-input-field">
              <Lock size={20} className="signup-icon" />
              <input
                name="confirmPassword"
                type={showPassword ? "text" : "password"}
                placeholder="Repeat Password"
                onChange={handleChange}
                required
              />
            </div>
            {error && <p className="signup-error-msg">{error}</p>}
          </div>

          <button
            type="submit"
            className="signup-submit-btn"
            disabled={loading || !isPasswordSecure()}
          >
            {loading ? "Creating..." : "Continue"}
          </button>
        </form>

        <div className="signup-flow-footer">
          <div className="signup-socials">
            <button className="signup-social-btn"><img src={googleIcon} alt="G" /></button>
            <button className="signup-social-btn"><img src={appleIcon} alt="A" /></button>
            <button className="signup-social-btn"><img src={facebookIcon} alt="F" /></button>
          </div>

          <p className="login-redirect">
            Already have an account? <Link to="/signin">Login</Link>
          </p>
        </div>
      </div>
    </div>
  );
}