import React, { useEffect } from 'react';

const TestAR = () => {
    useEffect(() => {
        console.log("TestAR component mounted successfully");
    }, []);

    return (
        <div style={{ width: '100vw', height: '100vh', background: 'red' }}>
            <iframe
                src="https://192.168.1.2:3000"
                title="AR"
                allow="camera; microphone; gyroscope; accelerometer; xr-spatial-tracking"
                style={{ width: '100%', height: '100%', border: 'none' }}
                onError={() => console.log("Iframe failed to load")}
            />
        </div>
    );
};

export default TestAR;